CREATE EXTENSION IF NOT EXISTS pgcrypto;
CREATE TABLE citizens (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), run VARCHAR(12) UNIQUE NOT NULL, full_name VARCHAR(160) NOT NULL, email VARCHAR(160) NOT NULL, phone VARCHAR(32), created_at TIMESTAMP NOT NULL DEFAULT now());
CREATE TABLE procedures (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), citizen_id UUID REFERENCES citizens(id), name VARCHAR(180) NOT NULL, status VARCHAR(40) NOT NULL, owner VARCHAR(120) NOT NULL, updated_at TIMESTAMP NOT NULL DEFAULT now());
CREATE TABLE notifications (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), citizen_id UUID REFERENCES citizens(id), procedure_id UUID REFERENCES procedures(id), subject VARCHAR(180) NOT NULL, priority VARCHAR(24) NOT NULL, read_at TIMESTAMP);
CREATE TABLE sessions (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), citizen_id UUID REFERENCES citizens(id), device VARCHAR(100) NOT NULL, location VARCHAR(100), active BOOLEAN NOT NULL DEFAULT true, trusted BOOLEAN NOT NULL DEFAULT false);
CREATE TABLE consents (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), citizen_id UUID REFERENCES citizens(id), institution VARCHAR(140) NOT NULL, data_scope VARCHAR(140) NOT NULL, status VARCHAR(40) NOT NULL, expires_at DATE);
CREATE TABLE cases (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), citizen_id UUID REFERENCES citizens(id), procedure_id UUID REFERENCES procedures(id), status VARCHAR(40) NOT NULL, responsible VARCHAR(120));
CREATE TABLE audit_events (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), citizen_id UUID REFERENCES citizens(id), event_type VARCHAR(80) NOT NULL, detail TEXT NOT NULL, created_at TIMESTAMP NOT NULL DEFAULT now());
CREATE TABLE credentials (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), code VARCHAR(80) UNIQUE, name VARCHAR(180) NOT NULL, status VARCHAR(40) NOT NULL DEFAULT 'activo', metadata JSONB NOT NULL DEFAULT '{}', created_at TIMESTAMP NOT NULL DEFAULT now());
CREATE TABLE mfa_methods (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), code VARCHAR(80) UNIQUE, name VARCHAR(180) NOT NULL, status VARCHAR(40) NOT NULL DEFAULT 'activo', metadata JSONB NOT NULL DEFAULT '{}', created_at TIMESTAMP NOT NULL DEFAULT now());
CREATE TABLE services (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), code VARCHAR(80) UNIQUE, name VARCHAR(180) NOT NULL, status VARCHAR(40) NOT NULL DEFAULT 'activo', metadata JSONB NOT NULL DEFAULT '{}', created_at TIMESTAMP NOT NULL DEFAULT now());
CREATE TABLE procedure_steps (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), code VARCHAR(80) UNIQUE, name VARCHAR(180) NOT NULL, status VARCHAR(40) NOT NULL DEFAULT 'activo', metadata JSONB NOT NULL DEFAULT '{}', created_at TIMESTAMP NOT NULL DEFAULT now());
CREATE TABLE digital_addresses (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), code VARCHAR(80) UNIQUE, name VARCHAR(180) NOT NULL, status VARCHAR(40) NOT NULL DEFAULT 'activo', metadata JSONB NOT NULL DEFAULT '{}', created_at TIMESTAMP NOT NULL DEFAULT now());
CREATE TABLE address_evidence (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), code VARCHAR(80) UNIQUE, name VARCHAR(180) NOT NULL, status VARCHAR(40) NOT NULL DEFAULT 'activo', metadata JSONB NOT NULL DEFAULT '{}', created_at TIMESTAMP NOT NULL DEFAULT now());
CREATE TABLE address_history (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), code VARCHAR(80) UNIQUE, name VARCHAR(180) NOT NULL, status VARCHAR(40) NOT NULL DEFAULT 'activo', metadata JSONB NOT NULL DEFAULT '{}', created_at TIMESTAMP NOT NULL DEFAULT now());
CREATE TABLE notification_preferences (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), code VARCHAR(80) UNIQUE, name VARCHAR(180) NOT NULL, status VARCHAR(40) NOT NULL DEFAULT 'activo', metadata JSONB NOT NULL DEFAULT '{}', created_at TIMESTAMP NOT NULL DEFAULT now());
CREATE TABLE message_attachments (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), code VARCHAR(80) UNIQUE, name VARCHAR(180) NOT NULL, status VARCHAR(40) NOT NULL DEFAULT 'activo', metadata JSONB NOT NULL DEFAULT '{}', created_at TIMESTAMP NOT NULL DEFAULT now());
CREATE TABLE consent_requests (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), code VARCHAR(80) UNIQUE, name VARCHAR(180) NOT NULL, status VARCHAR(40) NOT NULL DEFAULT 'activo', metadata JSONB NOT NULL DEFAULT '{}', created_at TIMESTAMP NOT NULL DEFAULT now());
CREATE TABLE consent_history (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), code VARCHAR(80) UNIQUE, name VARCHAR(180) NOT NULL, status VARCHAR(40) NOT NULL DEFAULT 'activo', metadata JSONB NOT NULL DEFAULT '{}', created_at TIMESTAMP NOT NULL DEFAULT now());
CREATE TABLE case_events (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), code VARCHAR(80) UNIQUE, name VARCHAR(180) NOT NULL, status VARCHAR(40) NOT NULL DEFAULT 'activo', metadata JSONB NOT NULL DEFAULT '{}', created_at TIMESTAMP NOT NULL DEFAULT now());
