CREATE TABLE security_alerts (id UUID PRIMARY KEY DEFAULT gen_random_uuid(), code VARCHAR(80) UNIQUE, name VARCHAR(180) NOT NULL, status VARCHAR(40) NOT NULL DEFAULT 'activo', metadata JSONB NOT NULL DEFAULT '{}', created_at TIMESTAMP NOT NULL DEFAULT now());
